GUIJobExtractItem = class("GUIJobExtractItem", IGUIWindow)

function GUIJobExtractItem:onLoad()
    self.id = nil
    self.card = 0
    self.isOpen = false
    self.content = self:getChildWindow(0, GUIType.Layout)
    self.ivImage = self:getChildWindow(0, GUIType.StaticImage, self.content)
    self.ivIcon = self:getChildWindow(1, GUIType.EffectViewOfObtainment, self.content)

    self.ivName = self:getChildWindow(2, GUIType.StaticImage, self.content)
    self.ivName:SetVisible(false)
    self.tvName_text = self:getChildWindow(0, GUIType.StaticText, self.ivName)

    self.content:registerEvent(GUIEvent.TouchUp, function()
        self:onCardClick()
    end)
end

function GUIJobExtractItem:onCardClick()
    --When the card state is not turned, can be clicked
    if GUIJobExtract:isHaveIndex(self.index) then
        return
    end
    if GUIJobExtract.isCardOpen == false then
        return
    end
    GUIJobExtract.isCardOpen = false
    GUIJobExtract:changeIndex(self.index)
    GUIJobExtract:extractRandomJob()

end

function GUIJobExtractItem:setItemData(item)
    self.id = item.id
    self.card = item
    self.ivImage:SetVisible(false)
    self.ivIcon:SetImage(self.card.icon)

    self.ivName:SetVisible(true)
    self.tvName_text:SetText(Lang:getString(item.name))
    GUIJobExtract:changeSmallItemStatus(self.id)
end

function GUIJobExtractItem:initItem(index)
    self.index = index
end

